	pc.log.WithFields(logrus.Fields{
		logfields.K8sNamespace: namespace,
		logfields.K8sName:      name,
		"policy_count":         pc.policyCountByNamespace[namespace],
	}).Debug("Policy count decremented")

	return nil
}

// CheckQuota checks if a namespace has exceeded its policy quota.
// Returns nil if the quota has not been exceeded, or ErrQuotaExceeded if it has.
func (pc *PolicyQuotaController) CheckQuota(namespace string) error {
	if pc.maxPerNamespace == 0 {
		// 0 means unlimited
		return nil
	}

	pc.mu.RLock()
	defer pc.mu.RUnlock()

	count := pc.policyCountByNamespace[namespace]
	if count >= pc.maxPerNamespace {
		return fmt.Errorf("%w: namespace %q has %d policies, max allowed is %d",
			ErrQuotaExceeded, namespace, count, pc.maxPerNamespace)
	}

	return nil
}

// GetNamespaceCount returns the current number of policies in a namespace.
func (pc *PolicyQuotaController) GetNamespaceCount(namespace string) int {
	pc.mu.RLock()
	defer pc.mu.RUnlock()

	return pc.policyCountByNamespace[namespace]
}

